import { RepoType } from '../contract.js';

export const checkId = 'health-check';
export const name = 'Health Check Route';
export const appliesTo = ['deployable', 'server', 'framework'];

const HEALTH_PATTERNS = [
  /['"`\/]healthz?['"`\/]/i,
  /['"`\/]health[-_]?check['"`\/]/i,
  /['"`\/]status['"`\/]/i,
  /['"`\/]ready['"`\/]/i,
  /['"`\/]alive['"`\/]/i,
  /['"`\/]live['"`\/]/i,
  /['"`\/]ping['"`\/]/i,
  /['"`\/]up['"`\/]/i,
  /livenessProbe|readinessProbe|startupProbe/i,
  /under-pressure|terminus|lightship|healthCheck|HealthCheck/i,
  /get\s*\(\s*['"`]\/health/i,
  /app\.(get|use|route|all)\s*\(\s*['"`]\/health/i,
  /router\.(get|use|all)\s*\(\s*['"`]\/health/i,
  /pathname\s*===?\s*['"`]\/health/i,
  /url\.pathname.*health/i,
  /event\.(path|node\.req\.url).*health/i,
  /defineEventHandler.*health/i,
];

const SERVER_DEPS = [
  'express', 'fastify', 'koa', 'restify', 'polka', 'connect', 'hapi', '@hapi/hapi',
  'micro', 'http-server', 'serve-static', 'json-server', 'next', 'nuxt', 'astro',
  '@astrojs/core', 'remix', '@remix-run/node', '@remix-run/serve', 'svelte-kit',
  '@sveltejs/kit', 'nitro', 'h3', 'hono', 'elysia', 'nest', '@nestjs/core',
  '@nestjs/common', '@nestjs/platform-express', 'cloudflare', '@cloudflare/workers-types',
  'wrangler', 'worktop', 'itty-router',
];

const HEALTH_LIBS = [
  '@nestjs/terminus', 'lightship', 'terminus', 'express-actuator',
  '@godaddy/terminus', 'under-pressure',
];

function scoreFile(path) {
  let score = 0;
  const lower = path.toLowerCase();
  const basename = lower.split('/').pop();

  if (/^(server|app|index|main)\.(js|ts|mjs|cjs)$/.test(basename)) score += 15;
  if (/\.(route|router|server|controller|handler|endpoint|middleware)\./.test(basename)) score += 6;

  if (/(^|\/)routes?\//.test(lower)) score += 8;
  if (/(^|\/)api\//.test(lower)) score += 10;
  if (/(^|\/)pages\/api\//.test(lower)) score += 12;
  if (/(^|\/)app\/api\//.test(lower)) score += 12;
  if (/(^|\/)server\/api\//.test(lower)) score += 12;
  if (/(^|\/)server\//.test(lower)) score += 6;
  if (/(^|\/)controllers?\//.test(lower)) score += 5;
  if (/(^|\/)handlers?\//.test(lower)) score += 4;
  if (/(^|\/)middleware\//.test(lower)) score += 4;
  if (/(^|\/)backend\//.test(lower)) score += 5;
  if (/(^|\/)workers?\//.test(lower)) score += 5;
  if (/(^|\/)apps?\//.test(lower)) score += 3;
  if (path.startsWith('src/')) score += 2;

  if (/\.(test|spec)\./i.test(path)) score -= 15;
  if (/(__tests__|__mocks__|fixtures?|examples?|demo|playground|benchmark|docs|\.github|\.storybook|scripts|dist|build|coverage|storybook|bin|cli|config|vitest|jest|knip|lint|\.vscode)\//i.test(path)) score -= 10;
  if (/node_modules/.test(path)) score -= 20;
  if (/\.d\.ts$/.test(path)) score -= 15;

  const depth = path.split('/').length;
  if (depth > 6) score -= 2;
  if (depth > 9) score -= 5;

  return score;
}

export async function check(context) {
  const { tree, files, packageJson, repoType } = context;

  try {
    const hasStartScript = packageJson?.scripts && (
      'start' in packageJson.scripts ||
      'serve' in packageJson.scripts ||
      'deploy' in packageJson.scripts ||
      'preview' in packageJson.scripts
    );

    const hasDocker = tree.some(p => /^dockerfile/i.test(p) || /^docker-compose/i.test(p));
    const hasK8s = tree.some(p => /(^|\/)(k8s|kubernetes|helm|deploy|infra)\//i.test(p));
    const hasWrangler = tree.some(p => /^wrangler\.(toml|json)/i.test(p));
    const hasServerless = tree.some(p => /^serverless\.(yml|yaml|json|ts)/i.test(p) || /^samconfig\.toml/i.test(p) || /^template\.(yml|yaml)/i.test(p));
    const hasFly = tree.some(p => /^fly\.toml/i.test(p));
    const hasHeroku = tree.some(p => /^Procfile/i.test(p));

    const allDeps = { ...packageJson?.dependencies, ...packageJson?.devDependencies, ...packageJson?.peerDependencies };
    const hasServerDep = SERVER_DEPS.some(d => d in allDeps);
    const hasHealthLib = HEALTH_LIBS.some(l => l in allDeps);

    const hasApiDir = tree.some(p => /(^|\/)((src\/)?(api|pages\/api|app\/api|server\/api|routes|server|backend|controllers|handlers|middleware|workers|netlify\/functions|supabase\/functions|edge-functions))\//i.test(p));
    const hasRootServerFile = tree.some(p => /^(src\/)?(server|app|index|main)\.(js|ts|mjs|cjs)$/.test(p));

    const hasServerSignals = hasStartScript || hasDocker || hasK8s || hasWrangler || hasServerless || hasFly || hasHeroku || hasServerDep || hasApiDir || hasRootServerFile;

    const isPureLibraryOrTool = packageJson && (packageJson.main || packageJson.exports || packageJson.module || packageJson.types) && !hasStartScript && !hasDocker && !hasK8s && !hasWrangler && !hasServerless && !hasFly && !hasHeroku && !hasApiDir && !hasRootServerFile && !hasServerDep;

    if (repoType === RepoType.LIBRARY || repoType === RepoType.EMPTY) {
      return {
        checkId,
        status: 'not-applicable',
        confidence: 'high',
        message: 'Library or empty repository — no health route needed',
        findings: [],
      };
    }

    if ((repoType === 'framework' || repoType === 'tool') && isPureLibraryOrTool) {
      return {
        checkId,
        status: 'not-applicable',
        confidence: 'high',
        message: 'Framework or library source code without deployed server components',
        findings: [],
      };
    }

    if (!hasServerSignals) {
      return {
        checkId,
        status: 'not-applicable',
        confidence: 'high',
        message: 'No server-side code or deployment infrastructure detected',
        findings: [],
      };
    }

    const findings = [];

    const infraFiles = tree.filter(p => {
      const lower = p.toLowerCase();
      return /^dockerfile/.test(lower) ||
        /^docker-compose/.test(lower) ||
        (/\.(ya?ml|json)$/.test(lower) && /(^|\/)(k8s|kubernetes|helm|deploy|infra|\.github\/workflows)\//.test(lower));
    }).slice(0, 6);

    for (const filePath of infraFiles) {
      const content = await files.get(filePath);
      if (!content) continue;
      if (/\b(HEALTHCHECK|healthcheck|health_check|livenessProbe|readinessProbe|startupProbe)\b/i.test(content)) {
        return {
          checkId,
          status: 'pass',
          confidence: 'high',
          message: `Deployment health probe configured in ${filePath}`,
          findings: [{ file: filePath, issue: 'Health check or probe found in infrastructure' }],
        };
      }
    }

    if (packageJson) {
      const scripts = packageJson.scripts || {};
      for (const [name] of Object.entries(scripts)) {
        if (/^(health|healthcheck|status|ping|ready|alive)/i.test(name)) {
          return {
            checkId,
            status: 'pass',
            confidence: 'high',
            message: `Health check script detected: "${name}"`,
            findings: [{ file: 'package.json', issue: `Health script: ${name}` }],
          };
        }
      }

      if (hasHealthLib) {
        const lib = HEALTH_LIBS.find(l => l in allDeps);
        return {
          checkId,
          status: 'pass',
          confidence: 'high',
          message: `Health check library present: ${lib}`,
          findings: [{ file: 'package.json', issue: `Uses library: ${lib}` }],
        };
      }
    }

    const healthTermsRe = /(health|healthcheck|health-check|healthz|status|ready|alive|live|ping)/i;
    const serverContextRe = /(^|\/)((src\/)?(api|pages\/api|app\/api|app\/health|pages\/health|routes|server\/api|server|middleware|controllers|handlers|backend|workers|netlify\/functions|supabase\/functions|edge-functions))\//i;

    const healthFiles = tree.filter(p =>
      healthTermsRe.test(p) &&
      serverContextRe.test(p) &&
      !/\.d\.ts$/.test(p) &&
      !/node_modules/.test(p)
    ).slice(0, 6);

    for (const filePath of healthFiles) {
      const content = await files.get(filePath);
      if (content && content.trim().length > 0) {
        return {
          checkId,
          status: 'pass',
          confidence: 'high',
          message: `Health endpoint file found at ${filePath}`,
          findings: [{ file: filePath, issue: 'Health endpoint file present in API/server directory' }],
        };
      }
    }

    let candidates = tree
      .filter(p => /\.(js|ts|jsx|tsx|mjs|cjs)$/.test(p) && !/\.d\.ts$/.test(p) && !/node_modules/.test(p))
      .map(p => ({ path: p, score: scoreFile(p) }))
      .filter(f => f.score > 0)
      .sort((a, b) => b.score - a.score)
      .slice(0, 8)
      .map(f => f.path);

    if (candidates.length === 0) {
      candidates = tree.filter(p => /^(src\/)?(server|app|index|main)\.(js|ts|mjs|cjs)$/.test(p)).slice(0, 3);
    }

    let foundFile = null;

    for (const filePath of candidates) {
      if (healthFiles.includes(filePath)) continue;
      const content = await files.get(filePath);
      if (!content) {
        findings.push({ file: filePath, issue: 'File could not be read' });
        continue;
      }

      let matched = false;
      for (const pattern of HEALTH_PATTERNS) {
        if (pattern.test(content)) {
          matched = true;
          break;
        }
      }

      if (matched) {
        foundFile = filePath;
        findings.push({ file: filePath, issue: 'Health endpoint pattern detected in source' });
        break;
      } else {
        findings.push({ file: filePath, issue: 'Scanned for health endpoint — none detected' });
      }
    }

    if (foundFile) {
      return {
        checkId,
        status: 'pass',
        confidence: 'high',
        message: `Health check endpoint detected in ${foundFile}`,
        findings,
      };
    }

    return {
      checkId,
      status: 'fail',
      confidence: 'high',
      message: 'Server application or deployment detected with no health check endpoint or probe',
      findings: findings.length > 0 ? findings : [{ file: 'N/A', issue: 'No health endpoint found in scanned files' }],
    };

  } catch (err) {
    console.error(`[health-check] analysis error:`, err);
    return {
      checkId,
      status: 'check-it',
      confidence: 'low',
      message: `Error during health check analysis: ${err.message}`,
      findings: [{ file: 'N/A', issue: `Error: ${err.message}` }],
    };
  }
}
